#!/usr/bin/env node
/**
 * Copies the canonical shared assets (résumé PDFs, certificates, touch
 * icon) from /shared into each standalone universe's public/ folder.
 *
 * Why this exists: every universe (A–H) is its own deployable Vite app
 * with its own public/ folder, and each needs these files physically
 * present to serve them in dev/build. Rather than committing ~130MB of
 * identical certificate scans 7 times over (~1GB total), the real files
 * live once in /shared and this script fans them out. /shared is tracked
 * in git; each app's copies are gitignored and regenerated by this script.
 *
 * Runs automatically via each app's `predev`/`prebuild` npm hook, so a
 * fresh clone just works the first time you run `npm run dev` or
 * `npm run build` in any universe — no manual step required.
 */
import { cpSync, existsSync, rmSync } from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const root = path.dirname(path.dirname(fileURLToPath(import.meta.url)));
const shared = path.join(root, 'shared');

// Which certificates set each universe uses. A (Glass & Light) shipped with
// its own distinct filenames before this repo was reorganized; B through H
// share the common set.
const CERT_SET = {
  A: 'certificates-glass',
  B: 'certificates',
  C: 'certificates',
  D: 'certificates',
  E: 'certificates',
  F: 'certificates',
  G: 'certificates',
  H: 'certificates',
};

// Only apps that actually reference this file in their index.html get it.
const APPLE_TOUCH_ICON_APPS = ['B', 'C', 'D', 'E', 'F', 'G', 'H'];

const onlyArg = process.argv.find((a) => a.startsWith('--only='));
const only = onlyArg ? onlyArg.split('=')[1] : null;
const apps = only ? [only] : Object.keys(CERT_SET);

for (const app of apps) {
  const appPublic = path.join(root, app, 'public');
  if (!existsSync(appPublic)) {
    console.warn(`Skipping ${app}: ${appPublic} does not exist.`);
    continue;
  }

  const certSrc = path.join(shared, CERT_SET[app]);
  const certDest = path.join(appPublic, 'certificates');
  rmSync(certDest, { recursive: true, force: true });
  cpSync(certSrc, certDest, { recursive: true });

  cpSync(path.join(shared, 'Suraj_Resume.pdf'), path.join(appPublic, 'Suraj_Resume.pdf'));
  cpSync(path.join(shared, 'Suraj_Resume_1Page.pdf'), path.join(appPublic, 'Suraj_Resume_1Page.pdf'));

  if (APPLE_TOUCH_ICON_APPS.includes(app)) {
    cpSync(path.join(shared, 'apple-touch-icon.png'), path.join(appPublic, 'apple-touch-icon.png'));
  }

  console.log(`Synced shared assets -> ${app}/public`);
}
